#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    for (int i = 1; i <= N; i++) {
        printf("%d ", i);
    }
    printf("\n");
    for (int i = 2; i <= N; i++) {
        printf("%d ", i);
    }
    printf("1\n");
    return 0;
}

